import { beforeAll, describe, expect, it } from 'react-native-harness';
import { getEnforcing } from 'react-native/Libraries/TurboModule/TurboModuleRegistry';
import CompressorApi, {
  Audio,
  Image,
  UploadType,
  UploaderHttpMethod,
  Video,
  backgroundUpload,
  cancelUpload,
  clearCache,
  createVideoThumbnail,
  download,
  generateFilePath,
  getDetails,
  getFileSize,
  getImageMetaData,
  getRealPath,
  getVideoMetaData,
  uuidv4,
} from '../src';
import * as PublicApi from '../src';

type ReactNativeFsModule = {
  getConstants(): {
    CachesDirectoryPath: string;
  };
  exists(path: string): Promise<boolean>;
  writeFile(path: string, b64: string, options: Record<string, unknown>): Promise<void>;
};

const getTurboModule = <T>(name: string): T => {
  return getEnforcing<T>(name);
};

const ReactNativeFs = getTurboModule<ReactNativeFsModule>('ReactNativeFs');

const publicRuntimeExports = [
  'Audio',
  'Image',
  'UploadType',
  'UploaderHttpMethod',
  'Video',
  'backgroundUpload',
  'cancelUpload',
  'clearCache',
  'createVideoThumbnail',
  'download',
  'generateFilePath',
  'getDetails',
  'getFileSize',
  'getImageMetaData',
  'getRealPath',
  'getVideoMetaData',
  'uuidv4',
];

const imageFixtureBase64 =
  '';

const videoFixtureBase64 =
  '';

const audioFixtureBase64 =
  '';

let imageUri = '';
let videoUri = '';
let audioUri = '';

const writeFixture = async (fileName: string, base64: string) => {
  const path = `${ReactNativeFs.getConstants().CachesDirectoryPath}/${fileName}`;
  await ReactNativeFs.writeFile(path, base64, {});
  return `file://${path}`;
};

const expectFileOutput = async (uri: string) => {
  expect(typeof uri).toBe('string');
  expect(uri.length).toBeGreaterThan(0);

  const path = uri.replace('file://', '');
  await expect(ReactNativeFs.exists(path)).resolves.toBe(true);
};

describe('react-native-compressor native harness', () => {
  beforeAll(async () => {
    imageUri = await writeFixture('compressor-harness-image.jpg', imageFixtureBase64);
    videoUri = await writeFixture('compressor-harness-video.mp4', videoFixtureBase64);
    audioUri = await writeFixture('compressor-harness-audio.m4a', audioFixtureBase64);
  });

  it('exports the public API from src/index.tsx', () => {
    expect(Object.keys(CompressorApi).sort()).toEqual(publicRuntimeExports.sort());
    expect(Object.keys(PublicApi).sort()).toEqual(['default', ...publicRuntimeExports].sort());
    expect(CompressorApi.Video).toBe(Video);
    expect(CompressorApi.Audio).toBe(Audio);
    expect(CompressorApi.Image).toBe(Image);
    expect(CompressorApi.backgroundUpload).toBe(backgroundUpload);
    expect(CompressorApi.cancelUpload).toBe(cancelUpload);
    expect(CompressorApi.clearCache).toBe(clearCache);
    expect(CompressorApi.createVideoThumbnail).toBe(createVideoThumbnail);
    expect(CompressorApi.download).toBe(download);
    expect(CompressorApi.generateFilePath).toBe(generateFilePath);
    expect(CompressorApi.getDetails).toBe(getDetails);
    expect(CompressorApi.getFileSize).toBe(getFileSize);
    expect(CompressorApi.getImageMetaData).toBe(getImageMetaData);
    expect(CompressorApi.getRealPath).toBe(getRealPath);
    expect(CompressorApi.getVideoMetaData).toBe(getVideoMetaData);
    expect(CompressorApi.uuidv4).toBe(uuidv4);
    expect(CompressorApi.UploadType.MULTIPART).toBe(UploadType.MULTIPART);
    expect(CompressorApi.UploaderHttpMethod.PATCH).toBe(UploaderHttpMethod.PATCH);
  });

  it('generates native output file paths and resolves local file paths', async () => {
    const generatedPath = await generateFilePath('jpg');
    expect(generatedPath).toContain('.jpg');
    expect(generatedPath.startsWith('file://')).toBe(true);

    await expect(getRealPath(imageUri, 'image')).resolves.toBe(imageUri);
    await expect(getRealPath(videoUri, 'video')).resolves.toBe(videoUri);
  });

  it('compresses a real image fixture through the exported Image API', async () => {
    const output = await Image.compress(imageUri, {
      compressionMethod: 'manual',
      maxWidth: 8,
      maxHeight: 8,
      quality: 0.8,
    });

    await expectFileOutput(output);

    const metadata = await getImageMetaData(output);
    expect(metadata.ImageWidth).toBeGreaterThan(0);
    expect(metadata.ImageHeight).toBeGreaterThan(0);
    expect(metadata.size).toBeGreaterThan(0);
    expect(metadata.exif).toBeTruthy();

    await expect(getFileSize(output)).resolves.toMatch(/^\d+$/);
  });

  it('reads metadata from a real video fixture through the exported metadata API', async () => {
    const metadata = await getVideoMetaData(videoUri);
    expect(metadata.width).toBeGreaterThan(0);
    expect(metadata.height).toBeGreaterThan(0);
    expect(metadata.duration).toBeGreaterThan(0);
    expect(metadata.extension).toBe('mp4');
    expect(metadata.size).toBeGreaterThan(0);
  });

  it('creates and clears a thumbnail for a real video fixture', async () => {
    const thumbnail = await createVideoThumbnail(videoUri, {});

    expect(thumbnail.path).toContain('/thumbnails/');
    expect(thumbnail.mime).toBe('image/jpeg');
    expect(thumbnail.width).toBeGreaterThan(0);
    expect(thumbnail.height).toBeGreaterThan(0);
    await expectFileOutput(`file://${thumbnail.path}`);

    await expect(clearCache('thumbnails/')).resolves.toBe('done');
  });

  it('compresses a real audio fixture through the exported Audio API', async () => {
    const output = await Audio.compress(audioUri, { quality: 'low' });

    await expectFileOutput(output);
    await expect(getFileSize(output)).resolves.toMatch(/^\d+$/);
  });

  it('manages exported background task and cancellation APIs without crashing', async () => {
    const taskId = await Video.activateBackgroundTask();
    expect(taskId === null || typeof taskId === 'number').toBe(true);

    const deactivatedTask = await Video.deactivateBackgroundTask();
    expect(deactivatedTask == null).toBe(true);
    expect(() => Video.cancelCompression('missing-compression-id')).not.toThrow();
    expect(() => cancelUpload('', true)).not.toThrow();
  });

  it('covers exported validation and failure paths without network calls', async () => {
    await expect(Image.compress('')).rejects.toThrow('Compression value is empty');
    await expect(getFileSize('file:///missing-file.jpg')).rejects.toBeTruthy();
    await expect(backgroundUpload('https://example.invalid/upload', imageUri, {} as never)).rejects.toBeTruthy();
    await expect(getDetails(imageUri)).rejects.toBeTruthy();
  });

  it('generates uuid-like ids through the exported helper', () => {
    expect(uuidv4()).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/);
  });
});
